$f = 'src\App.jsx'
$c = Get-Content $f -Raw

$old = "            return <div key={dk} style={{background:bg,border:isToday?`"2px solid #6366f1`":`"1px solid #e2e8f0`",borderRadius:8,padding:`"4px 5px`",minHeight:52,cursor:`"pointer`",position:`"relative`",boxShadow:isToday?`"0 0 0 2px #eef2ff`":`"none`"}}`r`n              onClick={()=>{`r`n                if(codeActif===`"EFFACER`"){`r`n                  // Mode effacement : vide la journ`u00E9e`r`n                  setDay(dk, null);`r`n                } else if(codeActif){`r`n                  // Mode saisie rapide : applique ou efface le code actif`r`n                  setDay(dk, code===codeActif ? null : codeActif);`r`n                } else {`r`n                  // Mode cycle classique`r`n                  const codes=[`"`",`"M`",`"AM`",`"N`",`"J`",`"RP`",`"RU`",`"NU`",`"CA`",`"MA`",`"VT`",`"FOR`",`"DISPO`"];`r`n                  const cur=codes.indexOf(code||`"`");`r`n                  const next=codes[(cur+1)%codes.length];`r`n                  setDay(dk,next||null);`r`n                }`r`n              }}>`r`n              <div style={{fontSize:10,fontWeight:isToday?800:600,color:isToday?`"#6366f1`":isWE?`"#94a3b8`":`"#1e293b`",marginBottom:2}}>{dayNum}</div>`r`n              {en?.finNuit&&showData&&<div style={{fontSize:7,fontWeight:700,color:`"#1e3a8a`",background:`"#dbeafe`",borderRadius:3,padding:`"1px 3px`",textAlign:`"center`",lineHeight:1.4}}>🌙 fin nuit<br/><span style={{fontWeight:400,fontSize:6}}>libre</span></div>}`r`n              {code&&<div style={{fontSize:8,fontWeight:700,`r`n                color:getTc(code),`r`n                background:getColor(code),`r`n                borderRadius:4,padding:`"1px 4px`",display:`"inline-block`"}}>`r`n                {CODES_FETES[code]?``🩷 `${code}``:(eq?.label||code)?.slice(0,4)}`r`n              </div>}`r`n              {en?.equipe2&&(()=>{const eq2=EQ[en.equipe2]||EQ_COLORS[en.equipe2];return <div style={{fontSize:7,fontWeight:700,color:eq2?.textColor||eq2?.tc,background:eq2?.color||eq2?.bg,borderRadius:4,padding:`"1px 3px`",display:`"inline-block`",marginTop:1}}>🌙N</div>;})()} `r`n              {en?.jsCode&&en.jsCode!==code&&<div style={{fontSize:7,color:`"#94a3b8`",fontFamily:`"monospace`",marginTop:1,overflow:`"hidden`",textOverflow:`"ellipsis`",whiteSpace:`"nowrap`"}}>{en.jsCode}</div>}"

if ($c.Contains("return <div key={dk} style={{background:bg,border:isToday?")) {
    Write-Host "TEXTE TROUVE - remplacement en cours"
    
    $newContent = "            // Cases bicolores/tricolores`r`n            const hasFinNuit = !!(en?.finNuit && showData);`r`n            const hasDebutNuit = !!(en?.equipe2 && showData);`r`n            const isSandwich = hasFinNuit && hasDebutNuit;`r`n            const couleurNuit = getColor(`"N`");`r`n            const tcNuit = getTc(`"N`");`r`n            const posteLabel=(()=>{`r`n              if(!en?.jsCode||en.jsCode===code) return null;`r`n              const pm=[...POSTES_PRCI_3x8,...POSTES_PAR_3x8].find(p=>p.M===en.jsCode||p.AM===en.jsCode||p.N===en.jsCode);`r`n              if(pm) return pm.label;`r`n              const pj=POSTES_JOURNEE.find(p=>p.jsCode===en.jsCode);`r`n              if(pj) return pj.label.slice(0,8);`r`n              return en.jsCode.slice(0,6);`r`n            })();`r`n`r`n            return <div key={dk} style={{`r`n                border:isToday?`"2px solid #6366f1`":`"1px solid #e2e8f0`",`r`n                borderRadius:8, minHeight:52, cursor:`"pointer`",`r`n                position:`"relative`", overflow:`"hidden`",`r`n                display:`"flex`", flexDirection:`"column`",`r`n                boxShadow:isToday?`"0 0 0 2px #eef2ff`":`"none`",`r`n              }}`r`n              onClick={()=>{`r`n                if(codeActif===`"EFFACER`"){ setDay(dk,null);`r`n                } else if(codeActif){ setDay(dk,code===codeActif?null:codeActif);`r`n                } else {`r`n                  const codes=[`"`",`"M`",`"AM`",`"N`",`"J`",`"RP`",`"RU`",`"NU`",`"CA`",`"MA`",`"VT`",`"FOR`",`"DISPO`"];`r`n                  const cur=codes.indexOf(code||`"`");`r`n                  const next=codes[(cur+1)%codes.length];`r`n                  setDay(dk,next||null);`r`n                }`r`n              }}>`r`n              <div style={{position:`"absolute`",top:3,left:5,fontSize:10,fontWeight:isToday?800:600,`r`n                color:isToday?`"#6366f1`":isWE?`"#94a3b8`":`"#1e293b`",zIndex:3,lineHeight:1.4}}>{dayNum}</div>`r`n`r`n              {isSandwich&&<>`r`n                <div style={{flex:1,background:couleurNuit,display:`"flex`",alignItems:`"center`",justifyContent:`"center`"}}>`r`n                  <span style={{fontSize:7,fontWeight:700,color:tcNuit}}>↓N</span>`r`n                </div>`r`n                <div style={{flex:1,background:`"#fff`",display:`"flex`",alignItems:`"center`",justifyContent:`"center`"}}>`r`n                  <span style={{fontSize:6,color:`"#cbd5e1`"}}>—</span>`r`n                </div>`r`n                <div style={{flex:1,background:couleurNuit,display:`"flex`",alignItems:`"center`",justifyContent:`"center`"}}>`r`n                  <span style={{fontSize:7,fontWeight:700,color:tcNuit}}>N↓</span>`r`n                </div>`r`n              </>}`r`n`r`n              {hasFinNuit&&!isSandwich&&!code&&<>`r`n                <div style={{flex:1,background:couleurNuit,display:`"flex`",alignItems:`"center`",justifyContent:`"center`"}}>`r`n                  <span style={{fontSize:7,fontWeight:700,color:tcNuit}}>↓N</span>`r`n                </div>`r`n                <div style={{flex:2,background:`"#fff`"}}/>`r`n              </>}`r`n`r`n              {hasDebutNuit&&!isSandwich&&<>`r`n                <div style={{flex:2,background:code&&showData?getColor(code):`"#f8fafc`",`r`n                  display:`"flex`",flexDirection:`"column`",alignItems:`"center`",justifyContent:`"center`",paddingTop:14,paddingBottom:2}}>`r`n                  {code&&showData&&<>`r`n                    <span style={{fontSize:8,fontWeight:800,color:getTc(code)}}>`r`n                      {CODES_FETES[code]?``🩷`${code}``:(EQ_COLORS[code]?.label||code)?.slice(0,4)}`r`n                    </span>`r`n                    {posteLabel&&<span style={{fontSize:6,color:getTc(code),opacity:.8,marginTop:1}}>{posteLabel}</span>}`r`n                  </>}`r`n                </div>`r`n                <div style={{flex:1,background:couleurNuit,display:`"flex`",alignItems:`"center`",justifyContent:`"center`"}}>`r`n                  <span style={{fontSize:7,fontWeight:700,color:tcNuit}}>N↓</span>`r`n                </div>`r`n              </>}`r`n`r`n              {!isSandwich&&!hasDebutNuit&&!(hasFinNuit&&!code)&&<>`r`n                <div style={{flex:1,background:code&&showData?getColor(code):`"transparent`",`r`n                  display:`"flex`",flexDirection:`"column`",justifyContent:`"center`",alignItems:`"center`",`r`n                  padding:`"4px 3px`",marginTop:14}}>`r`n                  {code&&showData&&<>`r`n                    <div style={{fontSize:8,fontWeight:800,color:getTc(code),textAlign:`"center`",lineHeight:1.3}}>`r`n                      {CODES_FETES[code]?``🩷`${code}``:(EQ_COLORS[code]?.label||code)?.slice(0,4)}`r`n                    </div>`r`n                    {posteLabel&&<div style={{fontSize:6,color:getTc(code),opacity:.8,marginTop:1,textAlign:`"center`",overflow:`"hidden`",textOverflow:`"ellipsis`",whiteSpace:`"nowrap`",maxWidth:`"100%`"}}>{posteLabel}</div>}`r`n                  </>}`r`n                  {hasFinNuit&&showData&&<div style={{fontSize:6,fontWeight:700,color:tcNuit,background:couleurNuit,borderRadius:3,padding:`"1px 3px`",marginTop:2}}>↓N</div>}`r`n                </div>`r`n              </>}"

    # Remplacer le bloc entier par ligne de debut
    $startMarker = "            return <div key={dk} style={{background:bg,border:isToday?"
    $endMarker = "              {en?.jsCode&&en.jsCode!==code&&<div style={{fontSize:7,color:`"#94a3b8`",fontFamily:`"monospace`",marginTop:1,overflow:`"hidden`",textOverflow:`"ellipsis`",whiteSpace:`"nowrap`"}}>{en.jsCode}</div>}"
    
    $startIdx = $c.IndexOf($startMarker)
    $endIdx = $c.IndexOf($endMarker)
    
    if ($startIdx -ge 0 -and $endIdx -ge 0) {
        $endIdx = $endIdx + $endMarker.Length
        $before = $c.Substring(0, $startIdx)
        $after = $c.Substring($endIdx)
        $c = $before + $newContent + $after
        Set-Content $f $c -NoNewline
        Write-Host "OK - cases bicolores + poste appliqué"
    } else {
        Write-Host "ERREUR - marqueurs de début/fin non trouvés: start=$startIdx end=$endIdx"
    }
} else {
    Write-Host "ERREUR - texte principal non trouve"
}
